import pdal
pipeline_json = {
  'pipeline': [
    'raw_forest.las',
    {'type': 'filters.csf', 'resolution': 1.0},  # ground filter
    {'type': 'filters.hag_nn'},  # height above ground
    {'type': 'writers.las', 'filename': 'normalized.las'}
  ]
}
pipeline = pdal.Pipeline(json.dumps(pipeline_json))
pipeline.execute()

-- TimescaleDB for forest stand time series
CREATE TABLE stand_metrics (
  time TIMESTAMPTZ,
  stand_id INT,
  mean_height_m FLOAT,
  basal_area_m2_ha FLOAT,
  crown_cover_pct FLOAT,
  health_score FLOAT
);
SELECT create_hypertable('stand_metrics', 'time');
